update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat gently on the stovetop or microwave.", "storage": "Keeps up to 4 days refrigerated or 3 months frozen.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the onion and garlic and saute in olive oil over medium until soft, about 4 minutes.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 4, "ingredient_refs": ["onions, raw", "garlic, raw", "olive oil"]}, {"n": 2, "temp": null, "text": "Add the ground beef and brown, breaking it up, about 6 minutes.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 6, "ingredient_refs": ["ground beef, 90% lean, raw"]}], "title": "Brown and build"}, {"steps": [{"n": 3, "temp": null, "text": "Add the cauliflower florets, diced tomatoes, and beef broth; bring to a simmer.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 3, "ingredient_refs": ["cauliflower, raw", "tomato products, canned, diced", "beef broth"]}, {"n": 4, "temp": null, "text": "Simmer gently until the cauliflower is tender and the stew thickens, about 25 minutes.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 25, "ingredient_refs": []}], "title": "Simmer"}], "make_ahead": "Tastes better the next day; make up to 4 days ahead.", "cook_time_min": 35, "prep_time_min": 10, "total_time_min": 45, "yield_servings": 1}'::jsonb where id='2ca07e17-a452-444d-924c-0944835aac12' and user_id is null;

