-- Mediterranean Lentil Tomato Soup
update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat gently on the stovetop.", "storage": "Keeps up to 4 days refrigerated or 3 months frozen.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the onion and garlic and saute in olive oil over medium until soft, about 4 minutes.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 4, "ingredient_refs": ["onions, raw", "garlic, raw", "olive oil"]}, {"n": 2, "temp": null, "text": "Stir in the cumin and toast for 30 seconds.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 1, "ingredient_refs": ["cumin, ground"]}], "title": "Build"}, {"steps": [{"n": 3, "temp": null, "text": "Add the cooked lentils, diced tomatoes, and a cup of water; season with sea salt and bring to a simmer.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 2, "ingredient_refs": ["lentils, mature seeds, cooked, boiled", "tomato products, canned, diced", "sea salt"]}, {"n": 4, "temp": null, "text": "Simmer until thickened, about 20 minutes; blend partially for a smoother soup if you like.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 20, "ingredient_refs": []}], "title": "Simmer"}], "make_ahead": "Make up to 4 days ahead.", "cook_time_min": 27, "prep_time_min": 8, "total_time_min": 35, "yield_servings": 1}'::jsonb where id='d2798029-9afc-44b1-9a5e-459536b11f9d' and user_id is null;

