update recipes set recipe_kind='cooked', instructions='{"reheat": "Reheat gently so the fish does not overcook.", "storage": "Keeps up to 2 days refrigerated.", "sections": [{"steps": [{"n": 1, "temp": null, "text": "Dice the onion, garlic, and ginger and saute in olive oil until fragrant, about 4 minutes; stir in the cumin.", "type": "cook", "active": true, "appliance": "stovetop", "duration_min": 4, "ingredient_refs": ["onions, raw", "garlic, raw", "ginger root, raw", "olive oil", "cumin, ground"]}, {"n": 2, "temp": null, "text": "Add the diced tomatoes and coconut milk and simmer 8 minutes to make a sauce.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 8, "ingredient_refs": ["tomato products, canned, diced", "coconut milk"]}], "title": "Build the sauce"}, {"steps": [{"n": 3, "temp": null, "text": "Nestle the mahi-mahi into the sauce and simmer gently until it flakes, about 10 minutes.", "type": "cook", "active": false, "appliance": "stovetop", "duration_min": 10, "ingredient_refs": ["mahi-mahi, raw"]}], "title": "Cook the fish"}], "make_ahead": "Make the sauce up to 3 days ahead; cook the fish fresh.", "cook_time_min": 25, "prep_time_min": 10, "total_time_min": 35, "yield_servings": 1}'::jsonb where id='6c6b607a-3df7-4db4-a54c-b6a17e62ee79' and user_id is null;

